1140: // Called by the boot classloader to load classes
1141: InstanceKlass* ClassLoader::load_class(Symbol* name, PackageEntry* pkg_entry, bool search_append_only, TRAPS) {
1142:   assert(name != nullptr, "invariant");
1143: 
1144:   ResourceMark rm(THREAD);
1145:   HandleMark hm(THREAD);
1146: 
1147:   const char* const class_name = name->as_C_string();
1148: 
1149:   EventMarkClassLoading m("Loading class %s", class_name);
1150: 
1151:   const char* const file_name = file_name_for_class_name(class_name,
1152:                                                          name->utf8_length());
1153:   assert(file_name != nullptr, "invariant");
1154: 
1155:   // Lookup stream for parsing .class file
1156:   ClassFileStream* stream = nullptr;
1157:   s2 classpath_index = 0;
1158:   ClassPathEntry* e = nullptr;
1159: 
1160:   // If search_append_only is true, boot loader visibility boundaries are
1161:   // set to be _first_append_entry to the end. This includes:
1162:   //   [-Xbootclasspath/a]; [jvmti appended entries]
1163:   //
1164:   // If search_append_only is false, boot loader visibility boundaries are
1165:   // set to be the --patch-module entries plus the base piece. This includes:
1166:   //   [--patch-module=<module>=<file>(<pathsep><file>)*]; [jimage | exploded module build]
1167:   //
1168: 
1169:   // Load Attempt #1: --patch-module
1170:   // Determine the class' defining module.  If it appears in the _patch_mod_entries,
1171:   // attempt to load the class from those locations specific to the module.
1172:   // Specifications to --patch-module can contain a partial number of classes
1173:   // that are part of the overall module definition.  So if a particular class is not
1174:   // found within its module specification, the search should continue to Load Attempt #2.
1175:   // Note: The --patch-module entries are never searched if the boot loader's
1176:   //       visibility boundary is limited to only searching the append entries.
1177:   if (_patch_mod_entries != nullptr && !search_append_only) {
1178:     assert(!CDSConfig::is_dumping_archive(), "CDS doesn't support --patch-module during dumping");
1179:     stream = search_module_entries(THREAD, _patch_mod_entries, pkg_entry, file_name);
1180:   }
1181: 
1182:   // Load Attempt #2: [jimage | exploded build]
1183:   if (!search_append_only && (nullptr == stream)) {
1184:     if (has_jrt_entry()) {
1185:       e = _jrt_entry;
1186:       stream = _jrt_entry->open_stream(THREAD, file_name);
1187:     } else {
1188:       // Exploded build - attempt to locate class in its defining module's location.
1189:       assert(_exploded_entries != nullptr, "No exploded build entries present");
1190:       assert(!CDSConfig::is_dumping_archive(), "CDS dumping doesn't support exploded build");
1191:       stream = search_module_entries(THREAD, _exploded_entries, pkg_entry, file_name);
1192:     }
1193:   }
1194: 
1195:   // Load Attempt #3: [-Xbootclasspath/a]; [jvmti appended entries]
1196:   if (search_append_only && (nullptr == stream)) {
1197:     // For the boot loader append path search, the starting classpath_index
1198:     // for the appended piece is always 1 to account for either the
1199:     // _jrt_entry or the _exploded_entries.
1200:     assert(classpath_index == 0, "The classpath_index has been incremented incorrectly");
